class Hero:
    def __init__(self, name, hp):
        self.name = name
        self.hp = hp

a = Hero("기사", 100)
print(a.name, a.hp)

class Dog:
    def __init__(self, name):
        self.name = name
    def bark(self):
        print(self.name, "멍멍")

d = Dog("바둑이")
d.bark()

class Monster:
    def __init__(self, hp):
        self.hp = hp
    def hit(self, dmg):
        self.hp = self.hp - dmg

m = Monster(50)
m.hit(10)
m.hit(15)
print(m.hp)

class Monster:
    def __init__(self, hp):
        self.hp = hp
    def hit(self, dmg):
        self.hp = self.hp - dmg

m = Monster(50)
m.hit(10)
m.hit(15)
print(m.hp)

class Car:
    def __init__(self, color, speed=0):
        self.color = color
        self.speed = speed

c = Car("red")
print(c.color, c.speed)

class Car:
    def __init__(self):
        self.speed = 0
    def up(self, a):
        self.speed = self.speed + a
    def stop(self):
        self.speed = 0

c = Car()
c.up(30)
c.up(20)
c.stop()
c.up(5)
print(c.speed)

class Student:
    def __init__(self, name):
        [[]] = name
    def hello(self):
        print(self.name)

s = Student("민수")
s.hello()

class Counter:
    def __init__(self):
        self.cnt = 0
    def add([[]]):
        self.cnt = self.cnt + 1

c = Counter()
c.add()
c.add()
print(c.cnt)

class Account:
    def __init__(self, money):
        self.money = money
    def deposit(self, x):
        self.money = self.money + x
    def withdraw(self, x):
        self.money = self.money - x

class Item:
    def __init__(self, name, price):
        self.name = name
        self.price = price
    def info(self):
        print(f"{self.name}: {self.price}원")

it = Item("연필", 500)
it.info()

class Rect:
    def __init__(self, w, h):
        self.w = w
        self.h = h
    def area(self):
        return self.w * self.h

r = Rect(3, 4)
print(r.area())

class Calc:
    def __init__(self, x):
        self.x = x
    def double(self):
        self.x = self.x * 2

c = Calc(5)
result = c.double()
print(c.x, result)
